using Contoso.Services;

namespace Contoso.Services.Tests;

public interface IGreeter { string Greet(); }

public sealed class FriendlyGreeter : IGreeter
{
    public string Greet() => "Hello!";
}

public interface ILogger { void Log(string msg); }

public sealed class ConsoleLogger : ILogger
{
    public void Log(string msg) { }
}

[TestClass]
public sealed class ServiceRegistryTests
{
    private ServiceRegistry _registry = null!;

    [TestInitialize]
    public void Setup() => _registry = new ServiceRegistry();

    [TestMethod]
    public void Register_ThenResolve_ReturnsRegisteredInstance()
    {
        var greeter = new FriendlyGreeter();

        _registry.Register<IGreeter>(greeter);

        Assert.IsNotNull(_registry.Resolve<IGreeter>());
    }

    [TestMethod]
    public void Resolve_ReturnsSameInstanceThatWasRegistered()
    {
        var greeter = new FriendlyGreeter();

        _registry.Register<IGreeter>(greeter);

        Assert.AreSame(greeter, _registry.Resolve<IGreeter>());
    }

    [TestMethod]
    public void Resolve_UnregisteredService_ReturnsNull()
    {
        Assert.IsNull(_registry.Resolve<IGreeter>());
    }

    [TestMethod]
    public void Clear_RemovesAllRegistrations()
    {
        _registry.Register<IGreeter>(new FriendlyGreeter());
        _registry.Register<ILogger>(new ConsoleLogger());

        _registry.Clear();

        Assert.AreEqual(0, _registry.GetAll().Count);
    }

    [TestMethod]
    public void Remove_UnregistersService()
    {
        _registry.Register<IGreeter>(new FriendlyGreeter());

        _registry.Remove<IGreeter>();

        Assert.IsNull(_registry.Resolve<IGreeter>());
    }

    [TestMethod]
    public void Register_OverwritesPreviousRegistration()
    {
        var first = new FriendlyGreeter();
        var second = new FriendlyGreeter();

        _registry.Register<IGreeter>(first);
        _registry.Register<IGreeter>(second);

        Assert.AreSame(second, _registry.Resolve<IGreeter>());
    }

    [TestMethod]
    public void Register_NullService_ThrowsArgumentNullException()
    {
        Assert.ThrowsException<ArgumentNullException>(() =>
            _registry.Register<IGreeter>(null!));
    }

    [TestMethod]
    public void ResolveRequired_WhenNotRegistered_ThrowsInvalidOperationException()
    {
        Assert.ThrowsException<InvalidOperationException>(() =>
            _registry.ResolveRequired<IGreeter>());
    }

    [TestMethod]
    public void GetAll_ReturnsAllRegisteredServices()
    {
        var greeter = new FriendlyGreeter();
        var logger = new ConsoleLogger();

        _registry.Register<IGreeter>(greeter);
        _registry.Register<ILogger>(logger);

        var all = _registry.GetAll();

        Assert.AreEqual(2, all.Count);
        CollectionAssert.Contains(all.ToList(), greeter);
        CollectionAssert.Contains(all.ToList(), logger);
    }
}

